#include <bits/stdc++.h>
using namespace std;
const int N=2e5+5;
int n,m,a[N],sum=1,check[N];
priority_queue<int> p;
priority_queue<int,vector<int>,greater<int> > q;
int main(){
	scanf("%d%d",&n,&m);
	for(int i=1;i<=n;i++)
		scanf("%d",&a[i]);
	for(int i=1;i<=m;i++){
		int u;
		scanf("%d",&u);
		check[u]++;
	}
	for(int i=1;i<=n;i++){
		if(p.size()<sum)
			p.push(a[i]);
		else if(p.top()>a[i])
			q.push(p.top()),p.pop(),p.push(a[i]);
		else
			q.push(a[i]);
		while(check[i]--){
			printf("%d\n",p.top());
			if(q.size())
				p.push(q.top()),q.pop();
			sum++;
		}
	}
	return 0;
}
